mapper.insert:
MERGE INTO TREE_GROUP T USING (
SELECT #{item.id} AS id, #{item.parent} AS parent, #{item.text} AS text, #{item.idx} AS idx, #{item.accountDate} AS accountDate, #{item.folder,jdbcType=VARCHAR} AS folder FROM dual
) SRC ON (T.id = SRC.id) WHEN MATCHED THEN UPDATE SET T.PARENT = SRC.parent, T.TEXT = SRC.text, T.IDX = SRC.idx, T.FOLDER = SRC.folder, T.UPDATE_DT = SYSDATE WHEN NOT MATCHED THEN INSERT (ID, PARENT, TEXT, IDX, ACCOUNT_DATE, FOLDER) VALUES (SRC.id, SRC.parent, SRC.text, SRC.idx, SRC.accountDate, SRC.folder)

mapper.delete:
DELETE FROM TREE_GROUP
WHERE ID IN

    #{item.id}
